"crm.formula.desc27": "\u0938\u094d\u091f\u094d\u0930\u093f\u0902\u0917 \u0938\u0947 \u092a\u0939\u0932\u0947 \u0914\u0930 \u092c\u093e\u0926 \u092e\u0947\u0902 \u0916\u093e\u0932\u0940 \u091c\u0917\u0939\u094b\u0902 \u0915\u094b \u0928\u093f\u0915\u093e\u0932\u0924\u093e \u0939\u0948\u0902.",
"crm.formula.desc26": "\u0907\u0928\u092a\u0941\u091f \u0938\u094d\u091f\u094d\u0930\u093f\u0902\u0917 \u0915\u0947 \u0938\u092d\u0940 \u0905\u0915\u094d\u0937\u0930 \u0905\u092a\u0930\u0915\u0947\u0938 \u092e\u0947\u0902 \u092c\u0926\u0932\u0924\u093e \u0939\u0948\u0964",
"crm.formula.desc25": "\u0907\u0928\u092a\u0941\u091f \u0938\u094d\u091f\u094d\u0930\u093f\u0902\u0917 \u0915\u0947 \u0938\u092d\u0940 \u0905\u0915\u094d\u0937\u0930 \u0932\u094b\u0905\u0930\u0915\u0947\u0938 \u092e\u0947\u0902 \u092c\u0926\u0932\u0924\u093e \u0939\u0948\u0964",
