"crm.formula.desc23": "\u0905\u0917\u0930 \u0938\u094d\u091f\u094d\u0930\u093f\u0902\u0917 \u0916\u094b\u091c \u0938\u094d\u091f\u094d\u0930\u093f\u0902\u0917 \u0915\u0947 \u0938\u093e\u0925 \u0936\u0941\u0930\u0942 \u0939\u094b\u0924\u0940 \u0939\u0948 \u0924\u094b \u2018\u0938\u091a\u2019 \u0935\u093e\u092a\u0938 \u0915\u0930\u0924\u093e \u0939\u0948 \u0905\u0928\u094d\u092f\u0925\u093e \u2018\u091d\u0942\u0920\u2019 \u0935\u093e\u092a\u0938 \u0915\u0930\u0924\u093e \u0939\u0948\u0964",
"crm.formula.desc22": "\u0905\u0917\u0930 \u0938\u094d\u091f\u094d\u0930\u093f\u0902\u0917 1 \u0938\u094d\u091f\u094d\u0930\u093f\u0902\u0917 2 \u092e\u0947\u0902 \u0939\u0948 \u0924\u094b \u0938\u091a \u0935\u093e\u092a\u0938 \u0915\u0930\u0924\u093e \u0939\u0948, \u0905\u0928\u094d\u092f\u0925\u093e \u091d\u0942\u0920 \u0935\u093e\u092a\u0938 \u0915\u0930\u0924\u093e \u0939\u0948\u0964",
