"crm.formula.desc20": "\u0926\u0940\u092f\u0947 \u0939\u0941\u090f \u090f\u0915\u094d\u0938\u092a\u094d\u0930\u0947\u0936\u0928 \u0915\u093e \u0924\u093e\u0930\u094d\u0915\u093f\u0915 \u0928\u093f\u0937\u0947\u0927 \u0926\u0947\u0924\u093e \u0939\u0948 (\u0909\u0926\u093e: \u0905\u0917\u0930 \u090f\u0915\u094d\u0938\u094d\u092a\u094d\u0930\u0947\u0936\u0928 \u0938\u091a \u0939\u0948,\u0924\u094b \u091d\u0942\u0920 \u0935\u093e\u092a\u0938 \u0915\u0930\u0924\u093e \u0939\u0948)\u0964",
