"crm.formula.desc17": "\u0926\u0940 \u0917\u0908 \u0924\u093e\u0930\u0940\u0916 \u0915\u0947 \u0932\u093f\u090f \u0938\u092a\u094d\u0924\u093e\u0939 (1-7) \u0915\u0947 \u0926\u093f\u0928 \u0915\u094b \u0935\u093e\u092a\u0938 \u0915\u0930\u0924\u093e \u0939\u0948 \u091c\u0939\u093e\u0902 1 \u0930\u0935\u093f\u0935\u093e\u0930 \u0939\u0948, 2 \u0938\u094b\u092e\u0935\u093e\u0930 \u0939\u0948 \u0914\u0930 \u0935\u0948\u0938\u0947 \u0939\u0940 \u0906\u0917\u0947\u0964 (\u0909\u0926\u093e: \u0936\u0941\u0915\u094d\u0930\u0935\u093e\u0930 \u0915\u094b \u201c6\u201d \u0935\u093e\u092a\u0938 \u0915\u0930\u0947\u0917\u093e)",
"crm.formula.desc16": "\u0926\u0940 \u0917\u0908 \u0926\u093f\u0928 \u0915\u0947 \u0938\u093e\u0932 \u0935\u093e\u092a\u0938 \u0915\u0930\u0924\u093e \u0939\u0948\u0964",
"crm.formula.desc15": "\u0926\u093f\u090f \u0917\u090f \u0924\u093e\u0930\u0940\u0916 \u0915\u0947 \u092e\u0939\u0940\u0928\u0947 \u0915\u0940 \u0938\u0902\u0916\u094d\u092f\u093e \u0926\u0947\u0924\u093e \u0939\u0948\u0902. (\u0909\u0926\u093e: \u0905\u092a\u094d\u0930\u0948\u0932 5 \u0924\u093e\u0930\u0940\u0916 \u201c4\u201d \u0926\u0947\u0917\u093e)",
"crm.formula.desc14": "\u0926\u0940 \u0917\u0908 \u0938\u092e\u092f \u0915\u0947 \u0932\u093f\u090f \u092e\u093f\u0928\u091f \u0935\u093e\u092a\u0938 \u0915\u0930\u0924\u093e \u0939\u0948\u0964",
"crm.formula.desc13": "\u0926\u0940 \u0917\u0908 \u0938\u092e\u092f \u0915\u0947 \u0932\u093f\u090f \u0918\u0902\u091f\u0947 (24-\u0918\u0902\u091f\u0947 \u0918\u0921\u0940 \u092a\u094d\u0930\u093e\u0930\u0942\u092a) \u0935\u093e\u092a\u0938 \u0915\u0930\u0924\u093e \u0939\u0948\u0964",
"crm.formula.desc12": "\u0926\u093f\u090f \u0917\u090f \u0924\u093e\u0930\u0940\u0916 \u0915\u0947 \u092e\u0939\u0940\u0928\u0947 \u0915\u0947 \u0926\u093f\u0928 \u0915\u0940 \u0938\u0902\u0916\u094d\u092f\u093e \u0926\u0947\u0924\u093e \u0939\u0948\u0902. (\u0909\u0926\u093e: \u0905\u092a\u094d\u0930\u0948\u0932 5 \u0924\u093e\u0930\u0940\u0916 \u201c5\u201d \u0926\u0947\u0917\u093e)",
"crm.formula.desc11": "\u0938\u094d\u091f\u094d\u0930\u093f\u0902\u0917 \u092e\u0947\u0902 \u0916\u094b\u091c \u0905\u0915\u094d\u0937\u0930 \u0915\u093e \u0938\u0902\u0916\u094d\u092f\u093e \u0938\u094d\u0925\u093f\u0924\u093f \u0926\u0947\u0924\u093e \u0939\u0948\u0964",
